app.use(helmet());
app.use(cors({ origin: process.env.ALLOWED_ORIGIN ?? false }));
app.use(rateLimit({ windowMs: 60_000, max: 100 }));
```
Helmet sets secure HTTP headers (CSP, X-Frame-Options, etc.), CORS should be explicit (not `*`), and rate limiting mitigates brute-force/DoS.

### 2. Safely parse JSON with size limits
```js
app.use(express.json({ limit: '10kb' }));
```
Prevents large-payload DoS and stops Express from parsing unbounded bodies.

### 3. Validate input on every route that accepts user data
Even the current routes should validate query/path params. Use a schema validator like `zod` or `joi`:
```js
const { z } = require('zod');

const UserIdSchema = z.coerce.number().int().positive();

app.get('/users/:id', (req, res, next) => {
  const parsed = UserIdSchema.safeParse(req.params.id);
  if (!parsed.success) {
    return res.status(400).json({ error: 'Invalid user id' });
  }
  // ...
});
```
Never trust `req.query`, `req.params`, `req.body`, or `req.headers` directly.

### 4. Wrap async handlers and add a central error handler
Uncaught errors in async handlers crash the process (Express 4). Use a wrapper and a final error middleware:
```js
const asyncHandler = (fn) => (req, res, next) =>
  Promise.resolve(fn(req, res, next)).catch(next);

app.use((err, req, res, _next) => {
  // Log server-side, but never leak stack traces to clients
  console.error(err);
  const status = err.status ?? 500;
  res.status(status).json({ error: status === 500 ? 'Internal error' : err.message });
});
```

### 5. Don't leak sensitive data in responses
`/users` currently returns email addresses. Only expose fields a client legitimately needs, and consider scrubbing PII based on the caller's auth scope.

### 6. Add authentication/authorization
`/users` is unauthenticated. At minimum, protect it with a middleware that verifies a bearer token or session before returning user data.

### 7. Make configuration environment-driven
```js
const PORT = Number(process.env.PORT) || 3000;
```
Hard-coding `3000` is fine for dev but shouldn't ship. Also disable `x-powered-by`:
```js
app.disable('x-powered-by');
```

### 8. Handle process-level failures
```js
process.on('unhandledRejection', (reason) => { console.error(reason); process.exit(1); });
process.on('uncaughtException', (err) => { console.error(err); process.exit(1); });
```
And support graceful shutdown on `SIGTERM`/`SIGINT` so in-flight requests complete.

### 9. 404 handler
Catch unmatched routes so they return a controlled JSON 404 instead of the default HTML:
```js
app.use((req, res) => res.status(404).json({ error: 'Not found' }));
```

### 10. Don't call `app.listen` when the module is imported for tests
```js
if (require.main === module) {
  app.listen(PORT, () => console.log(`Server running on ${PORT}`));
}
```
This prevents the listener from binding during unit tests or when the module is required elsewhere.

## Priority order
1. **Helmet + disable `x-powered-by`** (instant wins)
2. **Body size limit + rate limit** (DoS defense)
3. **Input validation with schemas** (injection/abuse defense)
4. **Central error handler that never leaks stack traces**
5. **Auth on `/users`** (before this ever touches real data)
6. Graceful shutdown + process error handlers
7. Env-driven config and test-friendly listen

