  const IdSchema = z.coerce.number().int().positive();
  app.get('/users/:id', (req, res, next) => {
    const parsed = IdSchema.safeParse(req.params.id);
    if (!parsed.success) return res.status(400).json({ error: 'Invalid id' });
    // ...
  });
  ```

## 3. Missing security middleware

**Issue:** No `helmet` (security headers), no rate limiting, no CORS policy, no compression, no request ID/logging.

**Suggested additions:**
```js
const helmet = require('helmet');
const rateLimit = require('express-rate-limit');
const cors = require('cors');

app.disable('x-powered-by');          // stop advertising Express
app.use(helmet());                    // CSP, HSTS, X-Frame-Options, etc.
app.use(cors({ origin: process.env.ALLOWED_ORIGIN || false })); // explicit allowlist
app.use(rateLimit({ windowMs: 60_000, max: 100 }));             // basic DoS protection
```

## 4. Hardcoded configuration

**Issue:** Port `3000` is hardcoded. No configuration from environment, so secrets and environment-specific values would likely end up in code later.

**Suggested change:**
```js
const PORT = Number(process.env.PORT) || 3000;
if (!Number.isInteger(PORT) || PORT < 1 || PORT > 65535) {
  throw new Error(`Invalid PORT: ${process.env.PORT}`);
}
